import{c as t,Q as a,j as r,m as s}from"./chunks/framework.BPKcPtvA.js";const n="/screenshots/admin-sidebar-light.png",o="/screenshots/admin-sidebar-dark.png",p=JSON.parse('{"title":"Admin Console Overview","description":"","frontmatter":{},"headers":[],"relativePath":"guide/admin/index.md","filePath":"guide/admin/index.md","lastUpdated":1778912818000}'),i={name:"guide/admin/index.md"};function d(l,e,c,h,g,m){return a(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="admin-console-overview" tabindex="-1">Admin Console Overview <a class="header-anchor" href="#admin-console-overview" aria-label="Permalink to &quot;Admin Console Overview&quot;">​</a></h1><p>The Admin Console is the workspace for Exto operators. It exposes every customer, tenant, instance, release, and billing record in the platform, gated by your internal role and scope.</p><h2 id="sidebar-map" tabindex="-1">Sidebar map <a class="header-anchor" href="#sidebar-map" aria-label="Permalink to &quot;Sidebar map&quot;">​</a></h2><p><img src="'+n+'" alt="Admin Console sidebar" class="light-only"><img src="'+o+'" alt="Admin Console sidebar" class="dark-only"></p><p>The left-hand sidebar is organised by domain:</p><table tabindex="0"><thead><tr><th>Section</th><th>What lives here</th></tr></thead><tbody><tr><td><strong>Dashboard</strong></td><td>Platform health and recent activity at a glance. See <a href="./dashboard">Dashboard</a>.</td></tr><tr><td><strong>Customers</strong></td><td>The companies you sell to. Create, suspend, churn, and manage. See <a href="./customers">Customers</a>.</td></tr><tr><td><strong>Tenants</strong></td><td>Customer environments running on instances. See <a href="./tenants">Tenants</a>.</td></tr><tr><td><strong>Tenant Insights</strong></td><td>Fleet-wide tenant usage analytics. See <a href="./tenant-insights">Tenant Insights</a>.</td></tr><tr><td><strong>Instances</strong></td><td>Hosted environments (clusters) that run tenants. See <a href="./instances">Instances</a>.</td></tr><tr><td><strong>Migrations</strong></td><td>Tenant clones, deletes, exports, imports, and instance replaces. See <a href="./migrations">Migrations</a>.</td></tr><tr><td><strong>Internal Users</strong></td><td>Exto operators and their roles. See <a href="./internal-users">Internal Users</a>.</td></tr><tr><td><strong>User Attributes</strong></td><td>Custom profile fields for customer users. See <a href="./user-attributes">User Attributes</a>.</td></tr><tr><td><strong>Releases</strong></td><td>New releases and their pipeline status. See <a href="./releases">Releases</a>.</td></tr><tr><td><strong>Release Configuration</strong></td><td>Global pipeline, approval, and SLA settings. See <a href="./release-configuration">Release Configuration</a>.</td></tr><tr><td><strong>Changelog</strong></td><td>Customer-facing release notes. See <a href="./changelog">Changelog</a>.</td></tr><tr><td><strong>Environment Variables</strong></td><td>Global variables and per-instance overrides. See <a href="./environment-variables">Environment Variables</a>.</td></tr><tr><td><strong>Finance</strong></td><td>Plans, meters, customers, invoices, payments, usage. See <a href="./finance/">Finance Overview</a>.</td></tr><tr><td><strong>Audit Log</strong></td><td>Every action recorded against its actor. See <a href="./audit-log">Audit Log</a>.</td></tr><tr><td><strong>Email Logs</strong></td><td>Outbound notification history. See <a href="./email-logs">Email Logs</a>.</td></tr><tr><td><strong>System → Workers</strong></td><td>Background worker health. See <a href="./system-workers">System Workers</a>.</td></tr><tr><td><strong>System → Discrepancies</strong></td><td>Triage inbox for dangling tenant data. See <a href="./discrepancies">Discrepancies</a>.</td></tr></tbody></table><h2 id="what-you-can-see" tabindex="-1">What you can see <a class="header-anchor" href="#what-you-can-see" aria-label="Permalink to &quot;What you can see&quot;">​</a></h2><p>Your internal role and <strong>scope</strong> determine what is visible:</p><ul><li><strong>Platform Admins</strong> and <strong>Infra Ops</strong> see everything across the platform.</li><li><strong>Account Managers</strong> see only customers in their scope. Other customers are hidden, not just locked.</li><li><strong>QA Admins</strong> see only customers in their customer scope and may operate on instances in their instance scope.</li></ul><p>See <a href="./../concepts/roles-and-permissions">Roles &amp; Permissions</a>.</p><h2 id="common-patterns" tabindex="-1">Common patterns <a class="header-anchor" href="#common-patterns" aria-label="Permalink to &quot;Common patterns&quot;">​</a></h2><p>The Admin Console is consistent across pages. Once you have used a few list views, the rest is familiar:</p><ul><li><strong>List pages</strong> show a toolbar (search, filter dropdowns, Clear button) above a sortable table. The count to the right of the toolbar shows filtered vs. total rows.</li><li><strong>Detail pages</strong> open from clicking a row. They have a header with status, a primary action set, and one or more tabs.</li><li><strong>Destructive actions</strong> (suspend, churn, archive, decommission, delete) always open a confirmation modal — usually with a required reason field.</li><li><strong>Status badges</strong> are colour-coded everywhere: green = healthy, orange = warning, red = problem, grey = retired.</li><li><strong>Timestamps</strong> are relative on lists (&quot;2 hours ago&quot;) and absolute on detail pages, with the full date available on hover.</li><li><strong>Row actions</strong> appear as icon buttons in the rightmost column, sometimes on hover.</li></ul><h2 id="focus-mode" tabindex="-1">Focus mode <a class="header-anchor" href="#focus-mode" aria-label="Permalink to &quot;Focus mode&quot;">​</a></h2><p>If you operate against a single customer for a while, click <strong>Focus on this customer</strong> on the customer&#39;s detail page. While focused, the Dashboard and other aggregate views narrow to just that customer&#39;s data. Exit focus from the same control.</p>',15)])])}const f=t(i,[["render",d]]);export{p as __pageData,f as default};
